import React, { useEffect, useState } from "react";
import MessageP from "./MessageP"


const MessageC = () => {

    const [messageDate, setMessageDate] = useState([])
    useEffect(() => { fetchMessage()}, [])

    const fetchMessage = async () => {
            fetch("http://localhost:3001/chat1")
            .then(response => response.json())
                .then((data) => {
                    if(data?.message.chat1){
                        setMessageDate(data.messages)
                        return
                    }
                        
                 })
        }
    return (
    <MessageP 
        text={messageDate.text}
        // author={messageDate.author.name}
        />)
}

export default MessageC;
